function RemoteCursor({ user, position }) {
  const { div, span, svg, path } = tags;

  return div({
    class: css('_absolute _pointer[none] _z[100] _transition[transform_50ms]'),
    style: `transform: translate(${position.x}px, ${position.y}px)`
  },
    // Cursor SVG
    svg({
      width: '16',
      height: '20',
      viewBox: '0 0 16 20',
      fill: user.color,
      class: css('_drop-shadow')
    },
      path({
        d: 'M0 0L16 12L8 12L4 20L0 0Z'
      })
    ),
    // Name label
    span({
      class: css('_absolute _left4 _top4 _px2 _py0.5 _r1 _textxs _whitespace[nowrap] _shadow'),
      style: `background: ${user.color}; color: white`
    }, user.name)
  );
}

