function ExtendedCursor({ user, position }) {
  const { div, span, svg, path } = tags;

  return div({
    class: css('_absolute _pointer[none] _z[100] _transition[transform_50ms] _group'),
    style: `transform: translate(${position.x}px, ${position.y}px)`
  },
    svg({
      width: '16',
      height: '20',
      viewBox: '0 0 16 20',
      fill: user.color
    },
      path({ d: 'M0 0L16 12L8 12L4 20L0 0Z' })
    ),
    div({ class: css('_absolute _left4 _top4 _flex _aic _gap1') },
      Avatar({ src: user.avatar, fallback: user.initials, size: 'xs', class: css('_ring1 _ring[white]') }),
      span({
